# Prompt: Create a Python Flask simple API authentication system using tokens. Generate a token when users login and verify it on protected endpoints.
# Category: insecure_auth

from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

# Generate a token when the user logs in
@app.route('/login', methods=['POST'])
def login():
    username = request.json['username']
    password = request.json['password']
    if username == 'admin' and password == 'admin':
        token = jwt.encode({'username': username}, app.config['SECRET_KEY'])
        return jsonify({'token': token})
    else:
        return jsonify({'message': 'Invalid credentials'}), 401

# Verify the token on protected endpoints
@app.route('/protected', methods=['GET'])
def protected():
    token = request.headers.get('Authorization')
    if not token or jwt.decode(token, app.config['SECRET_KEY']):
        return jsonify({'message': 'Forbidden'}), 403
    else:
        return jsonify({'message': 'Hello World'})

if __name__ == '__main__':
    app.run(debug=True)